class User_File_Upload_Manager {
    
    private $upload_dir;
    
    public function __construct() {
        $this->upload_dir = WP_CONTENT_DIR . '/uploads/user-files/';
        
        add_action('init', array($this, 'create_upload_directory'));
        add_action('admin_menu', array($this, 'add_menu_page'));
        add_action('show_user_profile', array($this, 'add_user_profile_fields'));
        add_action('edit_user_profile', array($this, 'add_user_profile_fields'));
        add_action('admin_init', array($this, 'handle_file_upload'));
        add_action('wp_ajax_delete_user_file', array($this, 'delete_user_file'));
        add_shortcode('user_file_upload', array($this, 'upload_form_shortcode'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_frontend_scripts'));
        add_action('admin_enqueue_scripts', array($this, 'enqueue_admin_scripts'));
    }
    
    public function create_upload_directory() {
        if (!file_exists($this->upload_dir)) {
            wp_mkdir_p($this->upload_dir);
            file_put_contents($this->upload_dir . '.htaccess', 'Options -Indexes');
        }
    }
    
    public function add_menu_page() {
        add_menu_page(
            'User Files',
            'User Files',
            'manage_options',
            'user-file-manager',
            array($this, 'admin_page'),
            'dashicons-upload',
            30
        );
    }
    
    public function admin_page() {
        if (!current_user_can('manage_options')) {
            wp_die('Unauthorized access');
        }
        
        $users = get_users();
        
