        echo '<h1>User Files Manager</h1>';
        echo '<table class="wp-list-table widefat fixed striped">';
        echo '<thead><tr><th>User</th><th>Profile Picture</th><th>Documents</th><th>Actions</th></tr></thead>';
        echo '<tbody>';
        
        foreach ($users as $user) {
            $profile_picture = get_user_meta($user->ID, 'profile_picture', true);
            $documents = get_user_meta($user->ID, 'user_documents', true);
            
