            echo '<td>' . esc_html($user->display_name) . ' (' . esc_html($user->user_email) . ')</td>';
            echo '<td>';
            if ($profile_picture) {
                echo '<img src="' . esc_url($this->get_file_url($profile_picture)) . '" style="max-width:50px;max-height:50px;">';
            } else {
                echo 'No picture';
            }
            echo '</td>';
            echo '<td>';
            if ($documents && is_array($documents)) {
                echo count($documents) . ' file(s)';
            } else {
                echo '0 files';
            }
            echo '</td>';
            echo '<td><a href="' . admin_url('user-edit.php?user_id=' . $user->ID) . '">View/Edit</a></td>';
            echo '</tr>';
        }
        
        echo '</tbody></table>';
        echo '</div>';
    }
    
    public function add_user_profile_fields($user) {
