                            <button type="button" class="button delete-user-file" data-user-id="<?php echo $user->ID; ?>" data-file-type="profile_picture" data-filename="<?php echo esc_attr($profile_picture); ?>">Delete Picture</button>
                        </div>
                    <?php endif; ?>
                    <form method="post" enctype="multipart/form-data" style="margin-top:10px;">
