                <td>
                    <?php if ($documents && is_array($documents)): ?>
                        <ul style="margin-bottom:15px;">
                            <?php foreach ($documents as $doc): ?>
                                <li style="margin-bottom:8px;">
                                    <a href="<?php echo esc_url($this->get_file_url($doc)); ?>" target="_blank"><?php echo esc_html($doc); ?></a>
                                    <button type="button" class="button delete-user-file" data-user-id="<?php echo $user->ID; ?>" data-file-type="document" data-filename="<?php echo esc_attr($doc); ?>">Delete</button>
                                </li>
                            <?php endforeach; ?>
                        </ul>
                    <?php endif; ?>
                    <form method="post" enctype="multipart/form-data">
