                        <input type="hidden" name="user_id" value="<?php echo $user->ID; ?>">
                        <input type="file" name="user_document" accept=".pdf,.doc,.docx,.txt,.jpg,.jpeg,.png,.gif">
                        <input type="submit" name="upload_user_document" class="button button-primary" value="Upload Document">
