    public function handle_file_upload() {
        if (isset($_POST['upload_profile_picture']) && isset($_FILES['profile_picture'])) {
            if (!isset($_POST['profile_picture_nonce']) || !wp_verify_nonce($_POST['profile_picture_nonce'], 'upload_profile_picture')) {
                return;
            }
            
            $user_id = intval($_POST['user_id']);
            
            if (!current_user_can('edit_user', $user_id)) {
                return;
            }
            
            if ($_FILES['profile_picture']['error'] === UPLOAD_ERR_OK) {
                $file = $_FILES['profile_picture'];
                $allowed_types = array('image/jpeg', 'image/jpg', 'image/png', 'image/gif');
                
                if (in_array($file['type'], $allowed_types) && $file['size'] <= 10485760) {
                    $old_picture = get_user_meta($user_id, 'profile_picture', true);
                    if ($old_picture) {
                        $this->delete_file($user_id, $old_picture);
                    }
                    
                    $filename = $this->upload_file($file, $user_id, 'profile');
                    if ($filename) {
                        update_user_meta($user_id, 'profile_picture', $filename);
                        add_action('admin_notices', function() {
                            echo '<div class="notice notice-success"><p>Profile picture uploaded successfully!</p></div>';
                        });
                    }
                }
            }
        }
        
        if (isset($_POST['upload_user_document']) && isset($_FILES['user_document'])) {
            if (!isset($_POST['user_document_nonce']) || !wp_verify_nonce($_POST['user_document_nonce'], 'upload_user_document')) {
                return;
            }
            
            $user_id = intval($_POST['user_id']);
            
            if (!current_user_can('edit_user', $user_id)) {
                return;
            }
            
            if ($_FILES['user_document']['error'] === UPLOAD_ERR_OK) {
                $file = $_FILES['user_document'];
                $allowed_types = array(
                    'application/pdf',
                    'application/msword',
                    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                    'text/plain',
                    'image/jpeg',
                    'image/jpg',
                    'image/png',
                    'image/gif'
                );
                
                if (in_array($file['type'], $allowed_types) && $file['size'] <= 10485760) {
                    $filename = $this->upload_file($file, $user_id, 'document');
                    if ($filename) {
                        $documents = get_user_meta($user_id, 'user_documents', true);
                        if (!is_array($documents)) {
                            $documents = array();
                        }
                        $documents[] = $filename;
                        update_user_meta($user_id, 'user_documents', $documents);
                        add_action('admin_notices', function() {
                            echo '<div class="notice notice-success"><p>Document uploaded successfully!</p></div>';
                        });
                    }
                }
            }
        }
    }
    
    private function upload_file($file, $user_id, $type) {
        $user_dir = $this->upload_dir . $user_id . '/';
        
        if (!file_exists($user_dir)) {
            wp_mkdir_p($user_dir);
        }
        
        $extension = pathinfo($file['name'], PATHINFO_EXTENSION);
        $filename = $type . '_' . time() . '_' . wp_generate_password(8, false) . '.' . $extension;
        $filepath = $user_dir . $filename;
        
        if (move_uploaded_file($file['tmp_name'], $filepath)) {
            chmod($filepath, 0644);
            return $filename;
        }
        
        return false;
    }
    
    private function get_file_url($filename) {
        $user_id = get_current_user_id();
        if (is_admin() && isset($_GET['user_id'])) {
            $user_id = intval($_GET['user_id']);
        }
        return content_url('uploads/user-files/' . $user_id . '/' . $filename);
    }
    
    private function delete_file($user_id, $filename) {
        $filepath = $this->upload_dir . $user_id . '/' . $filename;
        if (file_exists($filepath)) {
            unlink($filepath);
        }
    }
    
    public function delete_user_file() {
        check_ajax_referer('delete_user_file', 'nonce');
        
        $user_id = intval($_POST['user_id']);
        $file_type = sanitize_text_field($_POST['file_type']);
        $filename = sanitize_file_name($_POST['filename']);
        
        if (!current_user_can('edit_user', $user_id)) {
            wp_send_json_error('Unauthorized');
        }
        
        $this->delete_file($user_id, $filename);
        
        if ($file_type === 'profile_picture') {
            delete_user_meta($user_id, 'profile_picture');
        } else {
            $documents = get_user_meta($user_id, 'user_documents', true);
            if (is_array($documents)) {
                $documents = array_diff($documents, array($filename));
                update_user_meta($user_id, 'user_documents', array_values($documents));
            }
        }
        
        wp_send_json_success('File deleted');
    }
    
    public function enqueue_admin_scripts($hook) {
        if ($hook === 'profile.php' || $hook === 'user-edit.php') {
            wp_enqueue_script('user-file-upload-admin', plugin_dir_url(__FILE__) . 'admin.js', array('jquery'), '1.0', true);
            wp_localize_script('user-file-upload-admin', 'userFileUpload', array(
                'ajax_url' => admin_url('admin-ajax.php'),
                'nonce' => wp_create_nonce('delete_user_file')
            ));
        }
    }
    
    public function enqueue_frontend_scripts() {
        wp_enqueue_script('user-file-upload-frontend', plugin_dir_url(__FILE__) . 'frontend.js', array('jquery'), '1.0', true);
        wp_localize_script('user-file-upload-frontend', 'userFileUpload', array(
            'ajax_url' => admin_url('admin-ajax.php'),
            'nonce' => wp_create_nonce('delete_user_file')
        ));
        wp_enqueue_style('user-file-upload-frontend', plugin_dir_url(__FILE__) . 'frontend.css', array(), '1.0');
    }
    
