                        <button type="button" class="delete-user-file-btn" data-user-id="<?php echo $user_id; ?>" data-file-type="profile_picture" data-filename="<?php echo esc_attr($profile_picture); ?>">Delete Picture</button>
                    </div>
                <?php endif; ?>
                <form method="post" enctype="multipart/form-data" class="file-upload-form">
                    <?php wp_nonce_field('upload_profile_picture_frontend', 'profile_picture_nonce_frontend'); ?>
                    <input type="hidden" name="user_id" value="<?php echo $user_id; ?>">
                    <input type="file" name="profile_picture_frontend" accept="image/*" required>
                    <input type="submit" name="upload_profile_picture_frontend" value="Upload Profile Picture">